VALUES
  ('optometrist-moex-01234', 'optometrist', 'optometrist-moex-110-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關角膜地圖儀，下列敘述何者錯誤？', '["以Placidodisc成像的系統，是藉由角膜淚液層的反射映像，來測量角膜前表面的地圖", "以裂隙掃描（slit-scanning）成像的系統，屬於反射映像地形圖（reflectiontopography），從角膜橫斷面的 資訊，可觀察角膜前後表面的輪廓", "Scheimpflug成像系統的設計，屬於投射式地形圖（projectiontopography），可擷取從角膜前表面到後表 面的影像", "結合Placidodisc與裂隙掃描系統的角膜地圖儀，可算出角膜弧度、角膜厚度及高度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:46+00:00", "source_pdf_sha1": "9f4b5d5e89b6", "answer_pdf_sha1": "8ffbde5a34ce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
